const files = $json.files;
if (!files || files.length === 0) {
  throw new Error('No se encontraron archivos en la carpeta de Drive. Asegúrate de subir el reporte semanal antes del lunes.');
}
const latest = files[0];
return [{ json: {
  fileId: latest.id,
  fileName: latest.name,
  createdTime: latest.createdTime
}}];

// Filtrar filas validas: deben tener Fecha y Paciente, no ser encabezado ni vacías
const allRows = $input.all().map(item => item.json);
const rows = allRows.filter(row => {
  const fecha = String(row['Fecha'] || '').trim();
  const paciente = String(row['Paciente'] || '').trim();
  return fecha && paciente
    && fecha.toLowerCase() !== 'fecha'
    && paciente.toLowerCase() !== 'paciente';
});
if (rows.length === 0) throw new Error('No se encontraron filas de citas validas');

// Parser robusto para pesos colombianos
// Soporta: 188.571 | 188.571,00 | $ 188.571,00 | 188571 | 188571.00
const parsePrice = (price) => {
  if (!price || price === '' || price === '-' || price === 'N/A') return 0;
  let str = String(price).replace(/[$\s]/g, '').trim();
  if (!str || str === '-') return 0;
  const hasPeriod = str.includes('.');
  const hasComma = str.includes(',');
  if (hasPeriod && hasComma) {
    if (str.lastIndexOf('.') > str.lastIndexOf(',')) {
      str = str.replace(/,/g, '');
    } else {
      str = str.replace(/\./g, '').replace(',', '.');
    }
  } else if (hasPeriod) {
    const parts = str.split('.');
    if (parts[parts.length - 1].length === 3) str = str.replace(/\./g, '');
  } else if (hasComma) {
    const parts = str.split(',');
    if (parts[parts.length - 1].length === 3) str = str.replace(/,/g, '');
    else str = str.replace(',', '.');
  }
  return parseFloat(str) || 0;
};

const fmt = (n) => Math.round(n).toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.');

let totalIngresos = 0;
const porEstado = {}, porServicio = {}, porAseguradora = {}, porOrigen = {}, fechas = [];

rows.forEach(row => {
  const precio = parsePrice(row['Precio']);
  totalIngresos += precio;
  const estado = String(row['Estado'] || 'Sin estado').trim();
  porEstado[estado] = (porEstado[estado] || 0) + 1;
  const srv = String(row['Servicios'] || 'Sin servicio').trim();
  if (!porServicio[srv]) porServicio[srv] = { count: 0, ingresos: 0 };
  porServicio[srv].count++;
  porServicio[srv].ingresos += precio;
  const aseg = String(row['Aseguradora'] || 'Particular').trim();
  porAseguradora[aseg] = (porAseguradora[aseg] || 0) + 1;
  const origen = String(row['Origen de la cita'] || 'Directo').trim();
  porOrigen[origen] = (porOrigen[origen] || 0) + 1;
  if (row['Fecha']) fechas.push(String(row['Fecha']));
});

const totalCitas = rows.length;
const promedioPorCita = totalCitas > 0 ? Math.round(totalIngresos / totalCitas) : 0;
const canceladas = (porEstado['Cancelada'] || 0) + (porEstado['Cancelado'] || 0);
const tasaCancelacion = totalCitas > 0 ? Math.round((canceladas / totalCitas) * 100) : 0;
const topServicios = Object.entries(porServicio).sort((a, b) => b[1].ingresos - a[1].ingresos).slice(0, 5).map(([nombre, d]) => ({ nombre, citas: d.count, ingresos: d.ingresos, ingresosStr: '$' + fmt(d.ingresos) }));
const topOrigenes = Object.entries(porOrigen).sort((a, b) => b[1] - a[1]).map(([origen, count]) => ({ origen, count }));
const topAseguradoras = Object.entries(porAseguradora).sort((a, b) => b[1] - a[1]).slice(0, 6).map(([nombre, count]) => ({ nombre, count }));
const periodo = fechas.length > 0 ? `${fechas[0]} al ${fechas[fechas.length - 1]}` : 'Semana actual';
return [{ json: { periodo, totalCitas, totalIngresos, totalIngresosStr: '$' + fmt(totalIngresos), promedioPorCita, promedioPorCitaStr: '$' + fmt(promedioPorCita), tasaCancelacion, canceladas, porEstado, topServicios, topAseguradoras, topOrigenes, generadoEn: new Date().toISOString() }}];

